async function seedModule2Questions() {
  try {
    await mongoose.connect(process.env.MONGODB_URI);
    console.log('Connected to MongoDB');

    // Find Module 2 - "Module 2: Files and Folders"
    const module = await Module.findOne({ title: /Files and Folders/i });
    if (!module) {
      console.log('Module "Files and Folders" not found');
      process.exit(1);
    }

    await AssignmentQuestion.deleteMany({ moduleId: module._id });
    console.log('Cleared existing questions for Module 2');

    const set1 = JSON.parse(set1JSON);
    const set2 = JSON.parse(set2JSON);
    const set3 = JSON.parse(set3JSON);

    const allQuestions = [...set1, ...set2, ...set3].map(q => ({
      ...q,
      moduleId: module._id
    }));

    await AssignmentQuestion.insertMany(allQuestions);
    console.log(`✅ Successfully seeded ${allQuestions.length} questions for Module 2`);

    process.exit(0);
  } catch (error) {
    console.error('Seeding error:', error);
    process.exit(1);
  }
}

seedModule2Questions();
